#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=10005;
int n,m,dis[N],cnt[N],vis[N];
struct node
{
	int v,w;
};
vector<node> g[N];
bool spfa()
{
	memset(dis,0x3f,sizeof(dis));
	dis[0]=0;
	queue<int> q;
	q.push(0);
	vis[0]=1;
	while(!q.empty()){
		int u=q.front();
		q.pop();
		vis[u]=0;
		for(int i=0;i<g[u].size();i++)
		{
			int v=g[u][i].v;
			if(dis[v]>dis[u]+g[u][i].w)
			{
				dis[v]=dis[u]+g[u][i].w;
				if(!vis[v])
				{
					q.push(v);
					vis[v]=1;
					cnt[v]++;
					if(cnt[v]>n) return 0;
				}
			}
		}
	}
	return 1;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m;
	for(int i=1;i<=m;i++)
	{
		int op,x,y,c;
		cin>>op>>x>>y;
		if(op==1)
		{
			cin>>c;
			g[x].push_back(node{y,-c});
		}
		else if(op==2)
		{
			cin>>c;
			g[y].push_back(node{x,c});
		}
		else
		{
			g[x].push_back(node{y,0});
			g[y].push_back(node{x,0});
		}
	}
	for(int i=1;i<=n;i++)
	{
		g[0].push_back(node{i,0});
	}
	if(spfa()) cout<<"Yes";
	else cout<<"No";
	return 0;
}
